// Validate secret and extract params
const data = $input.first().json;
const body = data.body || data;

const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');
const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const content_id = body.content_id;
if (!content_id) throw new Error('Missing required field: content_id');

return [{ json: { content_id } }];

// Read content row + merge brand data
const { content_id } = $input.first().json;

const baseUrl = $env.NOCODB_BASE_URL;
const token = $env.NOCODB_API_TOKEN;
const contentsId = $env.NOCODB_CONTENTS_TABLE_ID;
const brandsId = $env.NOCODB_BRANDS_TABLE_ID;

if (!contentsId) throw new Error('NOCODB_CONTENTS_TABLE_ID not set');

function nocoGet(urlStr, tkn) {
  return new Promise((resolve, reject) => {
    const lib = urlStr.startsWith('https') ? require('https') : require('http');
    const req = lib.request(urlStr, { method: 'GET', headers: { 'xc-token': tkn, 'Accept': 'application/json' } }, (res) => {
      let body = ''; res.on('data', c => body += c);
      res.on('end', () => { try { resolve(JSON.parse(body)); } catch(e) { reject(new Error('JSON: ' + body.slice(0,200))); } });
    });
    req.on('error', reject); req.end();
  });
}

const qs = encodeURIComponent(`(Id,eq,${content_id})`);
const contentResp = await nocoGet(`${baseUrl}/api/v2/tables/${contentsId}/records?where=${qs}&limit=1`, token);
const contentRow = (contentResp.list || [])[0];
if (!contentRow) throw new Error(`Content ${content_id} not found`);

const result = { ...contentRow, content_id: String(contentRow.Id) };

if (contentRow.brand_id && brandsId) {
  try {
    const bqs = encodeURIComponent(`(Id,eq,${contentRow.brand_id})`);
    const brandResp = await nocoGet(`${baseUrl}/api/v2/tables/${brandsId}/records?where=${bqs}&limit=1`, token);
    const brandRow = (brandResp.list || [])[0];
    if (brandRow) {
      result.brand_tone = brandRow.tone || '';
      result.brand_name = brandRow.name || '';
      result.brand_palette = brandRow.palette || '';
      result.brand_typography = brandRow.typography || '';
    }
  } catch(e) { console.error('brand fetch:', e.message); }
}

return [{ json: result }];
